UPDATE esg.tb_notice
SET subject = #{subject},
    content = #{content},
    hr_id = (select hr_id from esg.tb_hr_info where user_id = #{updatedBy}),
    disp_st_date = #{dispStDate},
    disp_ed_date = #{dispEdDate},
    notice_type = #{noticeType},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE clnt_id = #{clntId}
  AND write_dt = #{writeDt}
  AND doc_no = #{docNo}

